output.sparql:
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
SELECT ?sponsorLabel WHERE {
  wd:Q308683 p:P859 ?sponsorship .
  ?sponsorship ps:P859 ?sponsor .
  ?sponsorship pq:P580 ?startYear .
  OPTIONAL {
    ?sponsorship pq:P582 ?endYear
  }
  .
  FILTER(year(?startYear) <= 2019)
  FILTER(NOT EXISTS {
    ?sponsorship pq:P582 ?endYear
  }
  || year(?endYear) >= 2019)
}

args.sparql:
SELECT ?sponsorLabel WHERE {
  wd:Q308683 p:P859 ?sponsorship.
  ?sponsorship ps:P859 ?sponsor.
  ?sponsorship pq:P580 ?startYear.
  FILTER (?startYear >= "2019-01-01T00:00:00Z"^^xsd:dateTime && ?startYear <= "2019-12-31T23:59:59Z"^^xsd:dateTime)
  FILTER NOT EXISTS { ?sponsorship pq:P582 ?endYear }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

